    if (CastOpc == Instruction::PtrToInt && Ty->isIntegerTy()) {
      if (Instruction *I = dyn_cast<Instruction>(Op)) {
        if (I->getOpcode() == Instruction::GetElementPtr) {
          GetElementPtrInst *GEP = cast<GetElementPtrInst>(I);
          Value *Ptr = GEP->getPointerOperand();
          Value *Idx = GEP->getOperand(1); // assuming single index
          // Look for pattern: gep ptr, (end_addr - ptrtoint(ptr))
          if (MatchPattern(Idx, m_Sub(m_Value(), m_PtrToInt(m_Specific(Ptr)))))
            if (Instruction *Sub = dyn_cast<Instruction>(Idx)) {
              Value *EndAddr = Sub->getOperand(0);
              Value *PtrToInt = Sub->getOperand(1);
              if (isa<PtrToIntInst>(PtrToInt) && PtrToInt->getOperand(0) == Ptr)
                return EndAddr;
            }
        }
      }
    }

    // bitcast x -> x
    if (CastOpc == Instruction::BitCast)
      if (Op->getType() == Ty)
        return Op;

    return nullptr;
}

